import React, { useState, useEffect } from 'react';
import { ShoppingBag, Clock, CheckCircle, MapPin, ShoppingCart } from 'lucide-react';
import Carrito from './Carrito';
import SeguimientoPedido from './SeguimientoPedido';

const PanelCliente = () => {
  const [tab, setTab] = useState('tienda'); 
  const [ofertasPorLocal, setOfertasPorLocal] = useState({});
  const [cart, setCart] = useState([]);
  const [pedidos, setPedidos] = useState([]);
  const [busqueda, setBusqueda] = useState("");
  const [verCarrito, setVerCarrito] = useState(false);

  // Obtenemos el ID del usuario logueado desde el localStorage (guardado en Login.js)
  const currentUserId = localStorage.getItem('user-id');

  useEffect(() => {
    // 1. Cargar ofertas de locales
    const locales = JSON.parse(localStorage.getItem('mis-locales') || "[]");
    const agrupado = {};
    locales.forEach(l => {
      const ofs = JSON.parse(localStorage.getItem(`ofertas-local-${l.id}`) || "[]");
      if (ofs.length > 0) agrupado[l.nombre] = ofs.map(o => ({ ...o, nombreLocal: l.nombre }));
    });
    setOfertasPorLocal(agrupado);
    
    // 2. Cargar historial FILTRADO por el usuario actual
    const todosLosPedidos = JSON.parse(localStorage.getItem('historial-pedidos') || "[]");
    const misPedidos = todosLosPedidos.filter(p => p.clienteId === currentUserId);
    setPedidos(misPedidos);
  }, [currentUserId]);

  const handlePago = (total) => {
    if (cart.length === 0) return;

    const nuevoPedido = {
      id: `PED-${Date.now()}`,
      clienteId: currentUserId, // Marcamos el pedido con el ID del usuario actual
      total,
      fecha: new Date().toLocaleString(),
      estado: 'proceso',
      distancia: 0,
      direccion: busqueda || "Retiro en local",
      items: [...cart]
    };

    // Actualizamos la base de datos global en LocalStorage
    const todosLosPedidos = JSON.parse(localStorage.getItem('historial-pedidos') || "[]");
    const listaActualizadaGlobal = [nuevoPedido, ...todosLosPedidos];
    localStorage.setItem('historial-pedidos', JSON.stringify(listaActualizadaGlobal));
    
    // Actualizamos el estado local (que ya está filtrado por efecto del handlePago)
    setPedidos([nuevoPedido, ...pedidos]);
    setCart([]);
    setVerCarrito(false);
    setTab('proceso');
  };

  const finalizarPedido = (id) => {
    // Actualizamos en la base de datos global
    const todosLosPedidos = JSON.parse(localStorage.getItem('historial-pedidos') || "[]");
    const globalActualizado = todosLosPedidos.map(p => 
      p.id === id ? { ...p, estado: 'completado' } : p
    );
    localStorage.setItem('historial-pedidos', JSON.stringify(globalActualizado));

    // Actualizamos la vista local
    setPedidos(pedidos.map(p => p.id === id ? { ...p, estado: 'completado' } : p));
  };

  return (
    <div style={layout}>
      <aside style={sidebar}>
        <div style={logoEspacio}>
          <h2 style={{color: '#e67e22', margin: 0}}>OfertasAPP</h2>
          <small style={{color: '#64748b'}}>Hola, {localStorage.getItem('user-name')}</small>
        </div>
        <nav style={navItems}>
          <button onClick={() => {setTab('tienda'); setVerCarrito(false)}} style={tab === 'tienda' && !verCarrito ? btnActive : btn}><ShoppingBag size={20}/> Hacer mi pedido</button>
          <button onClick={() => {setVerCarrito(true); setTab('tienda')}} style={verCarrito ? btnActive : btn}><ShoppingCart size={20}/> Carrito ({cart.length})</button>
          <button onClick={() => {setTab('proceso'); setVerCarrito(false)}} style={tab === 'proceso' ? btnActive : btn}><Clock size={20}/> En Proceso</button>
          <button onClick={() => {setTab('historial'); setVerCarrito(false)}} style={tab === 'historial' ? btnActive : btn}><CheckCircle size={20}/> Historial</button>
        </nav>
      </aside>

      <main style={main}>
        {tab === 'tienda' && !verCarrito && (
          <>
            <div style={searchBox}>
              <MapPin size={20} color="#e67e22" />
              <input style={input} placeholder="¿A dónde enviamos hoy?" value={busqueda} onChange={(e) => setBusqueda(e.target.value)} />
            </div>
            {Object.keys(ofertasPorLocal).length === 0 ? (
              <p style={{textAlign: 'center', color: '#64748b'}}>No hay ofertas disponibles en este momento.</p>
            ) : (
              Object.keys(ofertasPorLocal).map(nombreLocal => (
                <div key={nombreLocal} style={{marginBottom: '30px'}}>
                  <h3 style={localLabel}>{nombreLocal}</h3>
                  <div style={scrollRow}>
                    {ofertasPorLocal[nombreLocal].map(o => (
                      <div key={o.id} style={card}>
                        <img src={o.imagen} style={img} alt={o.producto} />
                        <div style={{padding: '12px'}}>
                          <h4 style={{margin: '0 0 10px 0'}}>{o.producto}</h4>
                          <button style={btnAdd} onClick={() => setCart([...cart, o])}>Agregar ${o.precioNuevo}</button>
                        </div>
                      </div>
                    ))}
                  </div>
                </div>
              ))
            )}
          </>
        )}

        {verCarrito && (
          <div style={cartContainer}>
            <h2 style={{marginBottom: '20px'}}>Tu Carrito</h2>
            <Carrito cart={cart} setCart={setCart} distanciaReal={0} onCheckout={handlePago} />
          </div>
        )}

        {tab === 'proceso' && (
          <div style={centerCont}>
            <h2 style={{marginBottom: '20px'}}>Sigue tu pedido 🛵</h2>
            {pedidos.filter(p => p.estado === 'proceso').length === 0 ? (
              <p style={{color: '#64748b'}}>No tienes pedidos en curso.</p>
            ) : (
              pedidos.filter(p => p.estado === 'proceso').map(p => (
                <SeguimientoPedido key={p.id} pedido={p} onFinalizar={finalizarPedido} />
              ))
            )}
          </div>
        )}

        {tab === 'historial' && (
          <div style={centerCont}>
            <h2 style={{marginBottom: '20px'}}>Tus pedidos pasados</h2>
            {pedidos.filter(p => p.estado === 'completado').length === 0 ? (
               <p style={{color: '#64748b'}}>Aún no tienes pedidos completados.</p>
            ) : (
              pedidos.filter(p => p.estado === 'completado').map(p => (
                <div key={p.id} style={historialCard}>
                  <div>
                    <div style={{fontSize: '0.8rem', color: '#94a3b8'}}>{p.fecha}</div>
                    <strong>Pedido: {p.id}</strong>
                  </div>
                  <div style={{textAlign: 'right'}}>
                    <div style={{fontWeight: 'bold', color: '#1e293b'}}>${p.total}</div>
                    <span style={{color: '#27ae60', fontSize: '0.8rem'}}>✓ Entregado</span>
                  </div>
                </div>
              ))
            )}
          </div>
        )}
      </main>
    </div>
  );
};

